(function () {
  const expr = %s;

  function toStringValue(v) {
    if (typeof v === 'string') return v;
    if (v === undefined) return '';
    try {
      const s = JSON.stringify(v);
      if (typeof s === 'string') return s;
    } catch (_) {}
