def run_command(cmd, cmd_arguments):
    import subprocess
    import shlex

    if not isinstance(cmd, str):
        raise ValueError("cmd must be a string")
    cmd = cmd.strip()
    if not cmd:
        raise ValueError("cmd must be a non-empty string")

    if cmd_arguments is None:
        args_list = []
    else:
        try:
            args_list = list(cmd_arguments)
        except TypeError:
            raise ValueError("cmd_arguments must be an iterable of arguments")

    try:
        str_args = [str(a) for a in args_list]
    except Exception:
        raise ValueError("cmd_arguments contain values that cannot be converted to strings")

    try:
        parsed_cmd = shlex.split(cmd)
        if not parsed_cmd:
            raise ValueError("cmd must resolve to a non-empty executable")
    except Exception as e:
        raise ValueError(f"Failed to parse cmd: {e}")

    full_args = parsed_cmd + str_args

    try:
        completed = subprocess.run(
            full_args,
            capture_output=True,
            text=True
        )
    except FileNotFoundError:
        raise ValueError("Command not found or not executable")
    except Exception as e:
        raise ValueError(f"Failed to execute command: {e}")

    if completed.returncode != 0:
        err = completed.stderr.strip() or completed.stdout.strip() or f"Command exited with status {completed.returncode}"
        raise ValueError(err)

    return completed.stdout
